const mammoth = require('mammoth');
const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  try {
    const binaryData = item.binary?.data;

    if (!binaryData) {
      throw new Error("No binary data found in this item.");
    }

    // Pass the current index i, not hardcoded 0
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

    const result = await mammoth.extractRawText({ buffer });

    results.push({
      json: {
        filename: binaryData.fileName,
        extractedText: result.value,
        mimeType: binaryData.mimeType
      }
    });
  } catch (error) {
    results.push({
      json: {
        error: error.message,
        itemStatus: "failed"
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  try {
    const binaryData = item.binary?.data;
    if (!binaryData) throw new Error("No binary data found.");

    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const base64 = buffer.toString('base64');
    const filename = binaryData.fileName || `file_${i}`;

    results.push({
      json: {
        filename,
        base64,
        mimeType: binaryData.mimeType
      }
    });

  } catch (error) {
    results.push({
      json: {
        filename: item.binary?.data?.fileName || 'unknown',
        error: error.message,
        itemStatus: 'failed'
      }
    });
  }
}

return results;

